import { NextResponse } from "next/server";
import { loadSparklinesAll } from "@/lib/queries";

export const dynamic = "force-dynamic";

export async function GET() {
  try {
    const sparklines = await loadSparklinesAll();
    return NextResponse.json({ ok: true, sparklines });
  } catch (e) {
    console.error("[api/items/sparklines]", e);
    return NextResponse.json(
      { ok: false, sparklines: {}, error: "Datenbank nicht erreichbar." },
      { status: 500 }
    );
  }
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { formatMaterialName, formatMoney, formatPct } from "@/lib/format";

type Item = {
  material: string;
  price: number;
  startValue: number | null;
  minPrice: number | null;
  maxPrice: number | null;
  yesterday: number | null;
};

const SORTS = [
  { key: "price-desc", label: "Höchster Preis" },
  { key: "price-asc", label: "Niedrigster Preis" },
  { key: "change", label: "Größte Änderung" },
  { key: "name", label: "Name A–Z" },
] as const;

export default function ItemBrowser() {
  const [items, setItems] = useState<Item[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [sort, setSort] = useState<string>("price-desc");

  useEffect(() => {
    fetch("/api/items")
      .then((r) => r.json())
      .then((d) => {
        if (d.ok) setItems(d.items);
        else setError(d.error ?? "Fehler beim Laden.");
      })
      .catch(() => setError("Fehler beim Laden."));
  }, []);

  const filtered = useMemo(() => {
    if (!items) return [];
    const q = search.trim().toLowerCase().replace(/ /g, "_");
    let list = items.filter(
      (i) =>
        q.length === 0 ||
        i.material.toLowerCase().includes(q) ||
        formatMaterialName(i.material).toLowerCase().includes(search.trim().toLowerCase())
    );
    const changeOf = (i: Item) =>
      i.yesterday && i.yesterday > 0 ? Math.abs((i.price - i.yesterday) / i.yesterday) : 0;
    list = [...list];
    switch (sort) {
      case "price-desc":
        list.sort((a, b) => b.price - a.price);
        break;
      case "price-asc":
        list.sort((a, b) => a.price - b.price);
        break;
      case "change":
        list.sort((a, b) => changeOf(b) - changeOf(a));
        break;
      case "name":
        list.sort((a, b) =>
          formatMaterialName(a.material).localeCompare(formatMaterialName(b.material))
        );
        break;
    }
    return list;
  }, [items, search, sort]);

  return (
    <div className="flex flex-col gap-4">
      {/* Suche + Sortierung */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Item suchen…"
          className="w-full rounded-xl border border-white/10 bg-white/[0.04] px-4 py-2.5 text-sm outline-none placeholder:text-neutral-600 focus:border-emerald-400/50 sm:max-w-xs"
        />
        <div className="flex flex-wrap gap-2">
          {SORTS.map((s) => (
            <button
              key={s.key}
              onClick={() => setSort(s.key)}
              className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
                sort === s.key
                  ? "bg-emerald-500/15 text-emerald-300"
                  : "border border-white/10 text-neutral-400 hover:bg-white/5"
              }`}
            >
              {s.label}
            </button>
          ))}
        </div>
        {items && (
          <span className="text-sm text-neutral-500 sm:ml-auto">{filtered.length} Items</span>
        )}
      </div>

      {/* Grid */}
      {error ? (
        <div className="rounded-2xl border border-white/10 p-12 text-center text-neutral-500">
          {error}
        </div>
      ) : !items ? (
        <div className="rounded-2xl border border-white/10 p-12 text-center text-neutral-500">
          Lade…
        </div>
      ) : (
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
          {filtered.map((item) => {
            const change =
              item.yesterday && item.yesterday > 0
                ? ((item.price - item.yesterday) / item.yesterday) * 100
                : null;
            return (
              <Link
                key={item.material}
                href={`/items/${item.material.toLowerCase()}`}
                className="group rounded-2xl border border-white/10 bg-white/[0.03] p-4 transition-colors hover:border-emerald-400/40 hover:bg-emerald-400/5"
              >
                <div className="truncate text-sm font-semibold group-hover:text-emerald-300">
                  {formatMaterialName(item.material)}
                </div>
                <div className="mt-2 text-lg font-bold text-emerald-400">
                  ${formatMoney(item.price)}
                </div>
                <div className="mt-1 flex items-center justify-between text-xs">
                  {change !== null && Math.abs(change) >= 0.05 ? (
                    <span className={change > 0 ? "text-emerald-400" : "text-red-400"}>
                      {formatPct(change)} <span className="text-neutral-600">24h</span>
                    </span>
                  ) : (
                    <span className="text-neutral-600">± 0 % 24h</span>
                  )}
                  <span className="text-neutral-600">Verlauf →</span>
                </div>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import { formatMaterialName, formatMoney, formatPct } from "@/lib/format";
import ItemIcon from "@/components/ItemIcon";

type Item = {
  material: string;
  price: number;
  startValue: number | null;
  minPrice: number | null;
  maxPrice: number | null;
  yesterday: number | null;
};

type SparklinePoint = { day: string; price: number };

const SORTS = [
  { key: "price-desc", label: "Höchster Preis" },
  { key: "price-asc", label: "Niedrigster Preis" },
  { key: "change", label: "Größte Änderung" },
  { key: "name", label: "Name A–Z" },
] as const;

export default function ItemBrowser() {
  const [items, setItems] = useState<Item[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [search, setSearch] = useState("");
  const [sort, setSort] = useState<string>("price-desc");
  const [sparklines, setSparklines] = useState<Record<string, SparklinePoint[]>>({});

  useEffect(() => {
    fetch("/api/items")
      .then((r) => r.json())
      .then((d) => {
        if (d.ok) setItems(d.items);
        else setError(d.error ?? "Fehler beim Laden.");
      })
      .catch(() => setError("Fehler beim Laden."));

    fetch("/api/items/sparklines")
      .then((r) => r.json())
      .then((d) => { if (d.ok) setSparklines(d.sparklines); })
      .catch(() => {/* silent */});
  }, []);

  const filtered = useMemo(() => {
    if (!items) return [];
    const q = search.trim().toLowerCase().replace(/ /g, "_");
    let list = items.filter(
      (i) =>
        q.length === 0 ||
        i.material.toLowerCase().includes(q) ||
        formatMaterialName(i.material).toLowerCase().includes(search.trim().toLowerCase())
    );
    const changeOf = (i: Item) =>
      i.yesterday && i.yesterday > 0 ? Math.abs((i.price - i.yesterday) / i.yesterday) : 0;
    list = [...list];
    switch (sort) {
      case "price-desc":
        list.sort((a, b) => b.price - a.price);
        break;
      case "price-asc":
        list.sort((a, b) => a.price - b.price);
        break;
      case "change":
        list.sort((a, b) => changeOf(b) - changeOf(a));
        break;
      case "name":
        list.sort((a, b) =>
          formatMaterialName(a.material).localeCompare(formatMaterialName(b.material))
        );
        break;
    }
    return list;
  }, [items, search, sort]);

  return (
    <div className="flex flex-col gap-4">
      {/* Suche + Sortierung */}
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Item suchen…"
          className="w-full rounded-xl border border-white/10 bg-white/[0.04] px-4 py-2.5 text-sm outline-none placeholder:text-neutral-600 focus:border-emerald-400/50 sm:max-w-xs"
        />
        <div className="flex flex-wrap gap-2">
          {SORTS.map((s) => (
            <button
              key={s.key}
              onClick={() => setSort(s.key)}
              className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
                sort === s.key
                  ? "bg-emerald-500/15 text-emerald-300"
                  : "border border-white/10 text-neutral-400 hover:bg-white/5"
              }`}
            >
              {s.label}
            </button>
          ))}
        </div>
        {items && (
          <span className="text-sm text-neutral-500 sm:ml-auto">{filtered.length} Items</span>
        )}
      </div>

      {/* Grid */}
      {error ? (
        <div className="rounded-2xl border border-white/10 p-12 text-center text-neutral-500">
          {error}
        </div>
      ) : !items ? (
        <div className="rounded-2xl border border-white/10 p-12 text-center text-neutral-500">
          Lade…
        </div>
      ) : (
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
          {filtered.map((item) => {
            const change =
              item.yesterday && item.yesterday > 0
                ? ((item.price - item.yesterday) / item.yesterday) * 100
                : null;
            const spark = sparklines[item.material] ?? [];
            return (
              <Link
                key={item.material}
                href={`/items/${item.material.toLowerCase()}`}
                className="group flex flex-col rounded-2xl border border-white/10 bg-white/[0.03] p-4 transition-colors hover:border-emerald-400/40 hover:bg-emerald-400/5"
              >
                {/* Icon + Name */}
                <div className="flex items-center gap-2.5">
                  <ItemIcon material={item.material} size={28} className="shrink-0" />
                  <div className="truncate text-sm font-semibold group-hover:text-emerald-300">
                    {formatMaterialName(item.material)}
                  </div>
                </div>

                {/* Sparkline */}
                {spark.length > 1 && (
                  <MiniSparkline points={spark} className="mt-3" />
                )}

                {/* Preis + Änderung */}
                <div className="mt-2 text-lg font-bold text-emerald-400">
                  ${formatMoney(item.price)}
                </div>
                <div className="mt-1 flex items-center justify-between text-xs">
                  {change !== null && Math.abs(change) >= 0.05 ? (
                    <span className={change > 0 ? "text-emerald-400" : "text-red-400"}>
                      {formatPct(change)} <span className="text-neutral-600">24h</span>
                    </span>
                  ) : (
                    <span className="text-neutral-600">± 0 % 24h</span>
                  )}
                  <span className="text-neutral-600">Verlauf →</span>
                </div>
              </Link>
            );
          })}
        </div>
      )}
    </div>
  );
}

/** Winzige SVG-Sparkline für den Preisverlauf. */
function MiniSparkline({
  points,
  className = "",
}: {
  points: SparklinePoint[];
  className?: string;
}) {
  const W = 160;
  const H = 36;
  const prices = points.map((p) => p.price);
  const min = Math.min(...prices);
  const max = Math.max(...prices);
  const range = max - min || 1;

  const xs = points.map((_, i) => (i / (points.length - 1)) * W);
  const ys = prices.map((p) => H - ((p - min) / range) * (H - 4) - 2);

  const d =
    xs.map((x, i) => `${i === 0 ? "M" : "L"}${x.toFixed(1)},${ys[i].toFixed(1)}`).join(" ") +
    ` L${W},${H} L0,${H} Z`;

  const line = xs
    .map((x, i) => `${i === 0 ? "M" : "L"}${x.toFixed(1)},${ys[i].toFixed(1)}`)
    .join(" ");

  const isUp = prices[prices.length - 1] >= prices[0];
  const color = isUp ? "#34d399" : "#f87171";

  return (
    <svg
      viewBox={`0 0 ${W} ${H}`}
      className={`w-full ${className}`}
      style={{ height: H }}
      preserveAspectRatio="none"
    >
      <defs>
        <linearGradient id={`sg-${isUp}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity={0.3} />
          <stop offset="100%" stopColor={color} stopOpacity={0} />
        </linearGradient>
      </defs>
      <path d={d} fill={`url(#sg-${isUp})`} />
      <path d={line} fill="none" stroke={color} strokeWidth="1.5" />
    </svg>
  );
}

"use client";

import Link from "next/link";
import { useCallback, useEffect, useState } from "react";
import {
  Area,
  AreaChart,
  Bar,
  BarChart,
  CartesianGrid,
  ReferenceLine,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts";
import { formatMaterialName, formatMoney, formatTs } from "@/lib/format";

type Detail = {
  ok: boolean;
  error?: string;
  currentPrice: number | null;
  settings: {
    startValue: number;
    minPrice: number;
    maxPrice: number;
    trendDays: number;
    gravity: number;
  } | null;
  history: { ts: string; price: number; sold: number }[];
  changes: { changedAt: string; startValue: number; currentPrice: number }[];
};

const RANGES = [
  { key: "14d", label: "14 Tage" },
  { key: "30d", label: "30 Tage" },
  { key: "90d", label: "90 Tage" },
  { key: "all", label: "Alles" },
] as const;

export default function ItemDetail({ material }: { material: string }) {
  const [range, setRange] = useState<string>("14d");
  const [data, setData] = useState<Detail | null>(null);
  const [loading, setLoading] = useState(true);

  const load = useCallback(
    async (r: string) => {
      setLoading(true);
      try {
        const res = await fetch(`/api/items/${material}?range=${r}`);
        setData((await res.json()) as Detail);
      } catch {
        setData(null);
      } finally {
        setLoading(false);
      }
    },
    [material]
  );

  useEffect(() => {
    load(range);
  }, [range, load]);

  const name = formatMaterialName(material);
  // Änderungsmarker nur anzeigen, wenn sie im geladenen Zeitraum liegen
  const firstTs = data?.history[0]?.ts ?? null;
  const visibleChanges =
    data?.changes.filter((c) => firstTs !== null && c.changedAt >= firstTs) ?? [];

  return (
    <div className="flex flex-col gap-6">
      {/* Kopf */}
      <div className="flex flex-wrap items-end justify-between gap-4">
        <div>
          <Link href="/items" className="text-sm text-neutral-500 hover:text-neutral-300">
            ← Alle Items
          </Link>
          <h1 className="mt-1 text-3xl font-bold tracking-tight">{name}</h1>
          <div className="mt-1 font-mono text-sm text-neutral-500">{material}</div>
        </div>
        <div className="text-right">
          <div className="text-sm text-neutral-500">Aktueller Verkaufspreis</div>
          <div className="text-4xl font-extrabold text-emerald-400">
            {data?.currentPrice !== null && data?.currentPrice !== undefined
              ? `$${formatMoney(data.currentPrice)}`
              : "–"}
          </div>
        </div>
      </div>

      {/* Einstellungen */}
      {data?.settings && (
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          <InfoCard label="StartWert" value={`$${formatMoney(data.settings.startValue)}`} />
          <InfoCard label="Untergrenze" value={`$${formatMoney(data.settings.minPrice)}`} />
          <InfoCard label="Obergrenze" value={`$${formatMoney(data.settings.maxPrice)}`} />
          <InfoCard label="Trend-Zeitraum" value={`${data.settings.trendDays} Tage`} />
        </div>
      )}

      {/* Zeitraum */}
      <div className="flex gap-2">
        {RANGES.map((r) => (
          <button
            key={r.key}
            onClick={() => setRange(r.key)}
            className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
              range === r.key
                ? "bg-emerald-500/15 text-emerald-300"
                : "border border-white/10 text-neutral-400 hover:bg-white/5"
            }`}
          >
            {r.label}
          </button>
        ))}
      </div>

      {/* Preis-Graph */}
      <div className="rounded-2xl border border-white/10 bg-white/[0.03] p-4">
        <h2 className="mb-2 px-2 text-sm font-medium text-neutral-400">Preisverlauf</h2>
        {loading ? (
          <div className="flex h-72 items-center justify-center text-neutral-500">Lade…</div>
        ) : !data?.ok || data.history.length === 0 ? (
          <div className="flex h-72 items-center justify-center text-neutral-500">
            {data?.error ?? "Noch keine Verlaufsdaten für diesen Zeitraum."}
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={300}>
            <AreaChart data={data.history} margin={{ top: 8, right: 8, left: -8, bottom: 0 }}>
              <defs>
                <linearGradient id="price" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#34d399" stopOpacity={0.45} />
                  <stop offset="100%" stopColor="#34d399" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid stroke="rgba(255,255,255,0.06)" vertical={false} />
              <XAxis
                dataKey="ts"
                tickFormatter={formatTs}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
                minTickGap={60}
              />
              <YAxis
                domain={["auto", "auto"]}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
                tickFormatter={(v) => `$${v}`}
              />
              <Tooltip
                contentStyle={{
                  background: "#171717",
                  border: "1px solid rgba(255,255,255,0.1)",
                  borderRadius: 12,
                  color: "#ededed",
                }}
                labelFormatter={(ts) => formatTs(String(ts))}
                formatter={(value) => [`$${formatMoney(Number(value))}`, "Preis"]}
              />
              {/* Admin-Änderungen als Marker */}
              {visibleChanges.map((c, i) => (
                <ReferenceLine
                  key={i}
                  x={nearestTs(data.history, c.changedAt)}
                  stroke="#f59e0b"
                  strokeDasharray="4 4"
                  label={{
                    value: "Änderung",
                    fill: "#f59e0b",
                    fontSize: 10,
                    position: "insideTopRight",
                  }}
                />
              ))}
              <Area
                type="monotone"
                dataKey="price"
                stroke="#34d399"
                strokeWidth={2}
                fill="url(#price)"
              />
            </AreaChart>
          </ResponsiveContainer>
        )}
      </div>

      {/* Volumen-Graph */}
      {data?.ok && data.history.length > 0 && (
        <div className="rounded-2xl border border-white/10 bg-white/[0.03] p-4">
          <h2 className="mb-2 px-2 text-sm font-medium text-neutral-400">
            Verkauftes Volumen pro Lauf
          </h2>
          <ResponsiveContainer width="100%" height={160}>
            <BarChart data={data.history} margin={{ top: 4, right: 8, left: -8, bottom: 0 }}>
              <CartesianGrid stroke="rgba(255,255,255,0.06)" vertical={false} />
              <XAxis
                dataKey="ts"
                tickFormatter={formatTs}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
                minTickGap={60}
              />
              <YAxis
                allowDecimals={false}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
              />
              <Tooltip
                contentStyle={{
                  background: "#171717",
                  border: "1px solid rgba(255,255,255,0.1)",
                  borderRadius: 12,
                  color: "#ededed",
                }}
                labelFormatter={(ts) => formatTs(String(ts))}
                formatter={(value) => [String(value), "Verkauft"]}
                cursor={{ fill: "rgba(255,255,255,0.04)" }}
              />
              <Bar dataKey="sold" fill="rgba(52,211,153,0.5)" radius={[3, 3, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

/** Nächstliegenden Historie-Zeitstempel zu einem Änderungszeitpunkt finden
 *  (ReferenceLine braucht einen X-Wert, der in den Daten existiert). */
function nearestTs(history: { ts: string }[], target: string): string {
  let best = history[0]?.ts ?? target;
  for (const h of history) {
    if (h.ts <= target) best = h.ts;
    else break;
  }
  return best;
}

function InfoCard({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/[0.03] p-4 text-center">
      <div className="text-lg font-bold">{value}</div>
      <div className="mt-0.5 text-xs text-neutral-500">{label}</div>
    </div>
  );
}

