            <div>
              <h1 className="text-3xl font-bold tracking-tight">{name}</h1>
              <div className="mt-0.5 font-mono text-sm text-neutral-500">{material}</div>
            </div>
          </div>
        </div>
        <div className="text-right">
          <div className="text-sm text-neutral-500">Aktueller Verkaufspreis</div>
          <div className="text-4xl font-extrabold text-emerald-400">
            {data?.currentPrice !== null && data?.currentPrice !== undefined
              ? `$${formatMoney(data.currentPrice)}`
              : "–"}
          </div>
        </div>
      </div>

      {/* Einstellungen */}
      {data?.settings && (
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          <InfoCard label="StartWert" value={`$${formatMoney(data.settings.startValue)}`} />
          <InfoCard label="Untergrenze" value={`$${formatMoney(data.settings.minPrice)}`} />
          <InfoCard label="Obergrenze" value={`$${formatMoney(data.settings.maxPrice)}`} />
          <InfoCard label="Trend-Zeitraum" value={`${data.settings.trendDays} Tage`} />
        </div>
      )}

      {/* Zeitraum */}
      <div className="flex gap-2">
        {RANGES.map((r) => (
          <button
            key={r.key}
            onClick={() => setRange(r.key)}
            className={`rounded-lg px-3 py-1.5 text-sm font-medium transition-colors ${
              range === r.key
                ? "bg-emerald-500/15 text-emerald-300"
                : "border border-white/10 text-neutral-400 hover:bg-white/5"
            }`}
          >
            {r.label}
          </button>
        ))}
      </div>

      {/* Preis-Graph */}
      <div className="rounded-2xl border border-white/10 bg-white/[0.03] p-4">
        <h2 className="mb-2 px-2 text-sm font-medium text-neutral-400">Preisverlauf</h2>
        {loading ? (
          <div className="flex h-72 items-center justify-center text-neutral-500">Lade…</div>
        ) : !data?.ok || data.history.length === 0 ? (
          <div className="flex h-72 items-center justify-center text-neutral-500">
            {data?.error ?? "Noch keine Verlaufsdaten für diesen Zeitraum."}
          </div>
        ) : (
          <ResponsiveContainer width="100%" height={300}>
            <AreaChart data={data.history} margin={{ top: 8, right: 8, left: -8, bottom: 0 }}>
              <defs>
                <linearGradient id="price" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="0%" stopColor="#34d399" stopOpacity={0.45} />
                  <stop offset="100%" stopColor="#34d399" stopOpacity={0} />
                </linearGradient>
              </defs>
              <CartesianGrid stroke="rgba(255,255,255,0.06)" vertical={false} />
              <XAxis
                dataKey="ts"
                tickFormatter={formatTs}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
                minTickGap={60}
              />
              <YAxis
                domain={["auto", "auto"]}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
                tickFormatter={(v) => `$${v}`}
              />
              <Tooltip
                contentStyle={{
                  background: "#171717",
                  border: "1px solid rgba(255,255,255,0.1)",
                  borderRadius: 12,
                  color: "#ededed",
                }}
                labelFormatter={(ts) => formatTs(String(ts))}
                formatter={(value) => [`$${formatMoney(Number(value))}`, "Preis"]}
              />
              {/* Admin-Änderungen als Marker */}
              {visibleChanges.map((c, i) => (
                <ReferenceLine
                  key={i}
                  x={nearestTs(data.history, c.changedAt)}
                  stroke="#f59e0b"
                  strokeDasharray="4 4"
                  label={{
                    value: "Änderung",
                    fill: "#f59e0b",
                    fontSize: 10,
                    position: "insideTopRight",
                  }}
                />
              ))}
              <Area
                type="monotone"
                dataKey="price"
                stroke="#34d399"
                strokeWidth={2}
                fill="url(#price)"
              />
            </AreaChart>
          </ResponsiveContainer>
        )}
      </div>

      {/* Volumen-Graph */}
      {data?.ok && data.history.length > 0 && (
        <div className="rounded-2xl border border-white/10 bg-white/[0.03] p-4">
          <h2 className="mb-2 px-2 text-sm font-medium text-neutral-400">
            Verkauftes Volumen pro Lauf
          </h2>
          <ResponsiveContainer width="100%" height={160}>
            <BarChart data={data.history} margin={{ top: 4, right: 8, left: -8, bottom: 0 }}>
              <CartesianGrid stroke="rgba(255,255,255,0.06)" vertical={false} />
              <XAxis
                dataKey="ts"
                tickFormatter={formatTs}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
                minTickGap={60}
              />
              <YAxis
                allowDecimals={false}
                stroke="#525252"
                tick={{ fill: "#737373", fontSize: 12 }}
              />
              <Tooltip
                contentStyle={{
                  background: "#171717",
                  border: "1px solid rgba(255,255,255,0.1)",
                  borderRadius: 12,
                  color: "#ededed",
                }}
                labelFormatter={(ts) => formatTs(String(ts))}
                formatter={(value) => [String(value), "Verkauft"]}
                cursor={{ fill: "rgba(255,255,255,0.04)" }}
              />
              <Bar dataKey="sold" fill="rgba(52,211,153,0.5)" radius={[3, 3, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}
    </div>
  );
}

/** Nächstliegenden Historie-Zeitstempel zu einem Änderungszeitpunkt finden
 *  (ReferenceLine braucht einen X-Wert, der in den Daten existiert). */
function nearestTs(history: { ts: string }[], target: string): string {
  let best = history[0]?.ts ?? target;
  for (const h of history) {
    if (h.ts <= target) best = h.ts;
    else break;
  }
  return best;
}

function InfoCard({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-2xl border border-white/10 bg-white/[0.03] p-4 text-center">
      <div className="text-lg font-bold">{value}</div>
      <div className="mt-0.5 text-xs text-neutral-500">{label}</div>
    </div>
  );
}

"use client";

import { useState } from "react";

interface ItemIconProps {
  material: string;
  size?: number;
  className?: string;
}

/**
 * Zeigt das Minecraft-Textur-Icon für ein Material.
 * Versucht zuerst /textures/item/<name>.png, dann /textures/block/<name>.png.
 */
export default function ItemIcon({ material, size = 32, className = "" }: ItemIconProps) {
  const name = material.toLowerCase();
  const [src, setSrc] = useState(`/textures/item/${name}.png`);
  const [failed, setFailed] = useState(false);

  const handleError = () => {
    if (src.startsWith("/textures/item/")) {
      setSrc(`/textures/block/${name}.png`);
    } else {
      setFailed(true);
    }
  };

  if (failed) {
    return (
      <div
        className={`flex items-center justify-center rounded bg-white/5 text-neutral-600 ${className}`}
        style={{ width: size, height: size, fontSize: size * 0.45 }}
      >
        ?
      </div>
    );
  }

  return (
    // eslint-disable-next-line @next/next/no-img-element
    <img
      src={src}
      alt={name}
      width={size}
      height={size}
      onError={handleError}
      className={`object-contain pixelated ${className}`}
      style={{ imageRendering: "pixelated", width: size, height: size }}
    />
  );
}

import { query } from "./db";

/**
 * Alle Lese-Queries der Website an die Spiel-Datenbank.
 * Tabellen werden vom Minecraft-Netzwerk befüllt:
 *  - smpg_sell_prices        aktueller Verkaufspreis pro Item
 *  - smpg_dynamic_prices     Einstellungen des dynamischen Preissystems
 *  - smpg_price_history      Preis/Volumen pro Anpassungslauf (Graphen)
 *  - smpg_dynamic_price_log  Admin-Änderungen (Marker in Graphen)
 *  - server_statistics       Spielerzahlen alle 5 Minuten (Proxy)
 */

export type ItemRow = {
  material: string;
  price: number;
  startValue: number | null;
  minPrice: number | null;
  maxPrice: number | null;
  yesterday: number | null;
};

export async function loadItems(): Promise<ItemRow[]> {
  const rows = await query<{
    material: string;
    price: string;
    start_value: string | null;
    min_price: string | null;
    max_price: string | null;
  }>(
    `SELECT s.material, s.sell_price AS price,
            d.start_value, d.min_price, d.max_price
     FROM smpg_sell_prices s
     LEFT JOIN smpg_dynamic_prices d ON d.material = s.material
     ORDER BY s.material ASC`
  );

  // Preis von "vor 24h": letzter Historie-Eintrag, der älter als 1 Tag ist
  const yRows = await query<{ material: string; price: string }>(
    `SELECT h.material, h.price
     FROM smpg_price_history h
     JOIN (SELECT material, MAX(id) AS mid
           FROM smpg_price_history
           WHERE ts <= NOW() - INTERVAL 1 DAY
           GROUP BY material) t ON h.id = t.mid`
  );
  const yesterday = new Map(yRows.map((r) => [r.material, Number(r.price)]));

  return rows.map((r) => ({
    material: r.material,
    price: Number(r.price),
    startValue: r.start_value !== null ? Number(r.start_value) : null,
    minPrice: r.min_price !== null ? Number(r.min_price) : null,
    maxPrice: r.max_price !== null ? Number(r.max_price) : null,
    yesterday: yesterday.get(r.material) ?? null,
  }));
}

export type HistoryPoint = { ts: string; price: number; sold: number };
export type ChangeMarker = {
  changedAt: string;
  startValue: number;
  minPrice: number;
  maxPrice: number;
  currentPrice: number;
};

export async function loadItemDetail(material: string, days: number | null) {
  const params: (string | number)[] = [material];
  let where = "WHERE material = ?";
  if (days !== null) {
    where += " AND ts >= NOW() - INTERVAL ? DAY";
    params.push(days);
  }

  const history = await query<{ ts: string; price: string; sold: string }>(
    `SELECT ts, price, sold FROM smpg_price_history ${where} ORDER BY ts ASC, id ASC`,
    params
  );

  const changes = await query<{
    changed_at: string;
    start_value: string;
    min_price: string;
    max_price: string;
    current_price: string;
  }>(
    `SELECT changed_at, start_value, min_price, max_price, current_price
     FROM smpg_dynamic_price_log WHERE material = ? ORDER BY changed_at ASC, id ASC`,
    [material]
  );

  const settings = await query<{
    start_value: string;
    min_price: string;
    max_price: string;
    trend_days: number;
    gravity: string;
  }>(
    `SELECT start_value, min_price, max_price, trend_days, gravity
     FROM smpg_dynamic_prices WHERE material = ? LIMIT 1`,
    [material]
  );

  const current = await query<{ sell_price: string }>(
    `SELECT sell_price FROM smpg_sell_prices WHERE material = ? LIMIT 1`,
    [material]
  );

  return {
    material,
    currentPrice: current.length > 0 ? Number(current[0].sell_price) : null,
    settings:
      settings.length > 0
        ? {
            startValue: Number(settings[0].start_value),
            minPrice: Number(settings[0].min_price),
            maxPrice: Number(settings[0].max_price),
            trendDays: settings[0].trend_days,
            gravity: Number(settings[0].gravity),
          }
        : null,
    history: history.map(
      (h): HistoryPoint => ({ ts: h.ts, price: Number(h.price), sold: Number(h.sold) })
    ),
    changes: changes.map(
      (c): ChangeMarker => ({
        changedAt: c.changed_at,
        startValue: Number(c.start_value),
        minPrice: Number(c.min_price),
        maxPrice: Number(c.max_price),
        currentPrice: Number(c.current_price),
      })
    ),
  };
}

export type PlayerPoint = { t: number; avg: number; max: number };
export type ServerNow = { server: string; online: number; max: number };

/** Spielerzahlen-Verlauf: Summe über alle Server, gebuckelt. */
export async function loadPlayerHistory(
  sinceMs: number,
  bucketMs: number
): Promise<PlayerPoint[]> {
  const rows = await query<{ b: string; avg_total: string; max_total: string }>(
    `SELECT FLOOR(ts / ?) AS b,
            ROUND(AVG(total)) AS avg_total,
            MAX(total) AS max_total
     FROM (SELECT timestamp AS ts, SUM(online_players) AS total
           FROM server_statistics
           WHERE timestamp >= ?
           GROUP BY timestamp) x
     GROUP BY b ORDER BY b ASC`,
    [bucketMs, sinceMs]
  );
  return rows.map((r) => ({
    t: Number(r.b) * bucketMs + bucketMs / 2,
    avg: Number(r.avg_total),
    max: Number(r.max_total),
  }));
}

/** Aktuelle Spielerzahlen pro Server (letzter Snapshot). */
export async function loadServersNow(): Promise<ServerNow[]> {
  const rows = await query<{
    server_name: string;
    online_players: number;
    max_players: number;
  }>(
    `SELECT server_name, online_players, max_players
     FROM server_statistics
     WHERE timestamp = (SELECT MAX(timestamp) FROM server_statistics)
     ORDER BY server_name ASC`
  );
  return rows.map((r) => ({
    server: r.server_name,
    online: r.online_players,
    max: r.max_players,
  }));
}

/** Höchste Gesamt-Spielerzahl seit `sinceMs`. */
export async function loadPeak(sinceMs: number): Promise<number> {
  const rows = await query<{ peak: string | null }>(
    `SELECT MAX(total) AS peak
     FROM (SELECT SUM(online_players) AS total
           FROM server_statistics
           WHERE timestamp >= ?
           GROUP BY timestamp) x`,
    [sinceMs]
  );
  return rows.length > 0 && rows[0].peak !== null ? Number(rows[0].peak) : 0;
}

